// ===== JOB SEARCH CONFIG (CUSTOM FORM SCRAPE) =====
// Driven by the webhook POST body. Validates required fields and
// emits a single { json: config } item shaped like the scheduled
// scraper expects, so the rest of the chain (Split LinkedIn Queries,
// Run Apify, Normalize, Dedup + Score, Postgres, Slack) is unchanged.

const trigger = $input.first().json || {};
// n8n webhook puts the JSON body under .body
const body = (trigger.body && typeof trigger.body === 'object') ? trigger.body : trigger;

// --- Validate required fields ---
function fail(msg) { throw new Error('Custom scrape config error: ' + msg); }

let keywordList = [];
if (Array.isArray(body.keywords)) {
  keywordList = body.keywords.map(k => String(k || '').trim()).filter(Boolean);
} else if (typeof body.keywords === 'string') {
  keywordList = body.keywords.split(',').map(s => s.trim()).filter(Boolean);
}
if (keywordList.length === 0) fail('keywords is required (comma-separated string or array)');
if (keywordList.length > 20) fail('keywords list too long (max 20)');

const location = String(body.location || '').trim();
if (!location) fail('location is required');

// --- Normalize optional fields ---
const workplaceRaw = String(body.workplace_type || 'any').toLowerCase().trim();
let workTypes;
if (workplaceRaw === 'remote') workTypes = ['remote'];
else if (workplaceRaw === 'hybrid') workTypes = ['hybrid'];
else if (workplaceRaw === 'on-site' || workplaceRaw === 'onsite') workTypes = ['onsite'];
else workTypes = ['remote', 'hybrid']; // 'any' default

const salaryMinIn = Number(body.salary_min);
const salaryMin = Number.isFinite(salaryMinIn) && salaryMinIn > 0 ? salaryMinIn : 0;

const dateWindowRaw = String(body.date_window || 'week').toLowerCase().trim();
const dateMap = {
  '24h': 'past_24h', 'day': 'past_24h', 'past_24h': 'past_24h',
  'week': 'past_week', 'past_week': 'past_week',
  'month': 'past_month', 'past_month': 'past_month'
};
const datePosted = dateMap[dateWindowRaw] || 'past_week';

const pages = Math.max(1, Math.min(5, Number(body.pages) || 2));
const maxResultsPerSearch = pages * 25; // LinkedIn pagination baseline

const runLabel = String(body.run_label || '').trim().slice(0, 80);

// Hard cap on query fan-out to protect Apify spend
const HARD_QUERY_CAP = 10;
const requestedQueryCount = keywordList.length * workTypes.length;
if (requestedQueryCount > HARD_QUERY_CAP) {
  // Trim keywords from the tail rather than silently overflow
  const maxKw = Math.max(1, Math.floor(HARD_QUERY_CAP / workTypes.length));
  keywordList = keywordList.slice(0, maxKw);
}

const config = {
  workflowScope: 'custom_form',
  _runLabel: runLabel,
  _salaryFloor: salaryMin,
  _customRequest: {
    keywords: keywordList,
    location,
    workplace_type: workplaceRaw,
    salary_min: salaryMin,
    date_window: dateWindowRaw,
    pages,
    run_label: runLabel
  },

  linkedinSearches: [], // built below

  datePosted,
  maxResultsPerSearch,

  fetchFullDescription: true,
  enrichWithAI: false,
  actorProxyConfig: {},

  // Custom scrapes are ad-hoc; users decide cadence. No run guard.
  runGuardEnabled: false,
  runGuardMinMinutes: 0,

  maxQueriesPerRun: HARD_QUERY_CAP,

  safeMode: false,
  safeMaxQueries: 2,
  safeMaxResults: 10,
  safeFetchFullDescription: true,
  testMode: false,
  testMaxQueries: 2,
  testMaxResults: 10,
  testFetchFullDescription: false,

  // ---- Relevance scoring (consumed by the "Dedup and Score" node) ----
  scoring: {
    // Use the user's keywords as the title-match anchors so the
    // relevance score reflects what they actually searched for.
    titleKeywords: keywordList,
    partialKeywords: [
      'automation', 'ai', 'platform', 'data', 'integration', 'cloud'
    ],
    seniorityWords: [
      'senior', 'staff', 'principal', 'lead', 'architect'
    ],
    homeAreaKeywords: [],
    bonusJDKeywords: [],
    secondaryHubKeywords: [],
    salaryFloor: salaryMin,
    negativeTitlePatterns: ['\\b(intern|junior|entry.level)\\b'],
    highRelevanceThreshold: 60,
  },

  // Read from n8n's environment. Leave unset to disable Slack posts.
  slackWebhookUrl: $env.SLACK_WEBHOOK_URL || '',
};

const searches = [];
for (const kw of keywordList) {
  for (const wt of workTypes) {
    searches.push({
      keywords: kw,
      location,
      workType: wt,
      datePosted,
      maxResults: maxResultsPerSearch,
      scope: 'custom_form',
      planId: 'custom_' + (runLabel || 'unlabeled').replace(/[^a-z0-9_-]/gi, '_'),
      windowId: 'primary'
    });
  }
}
config.linkedinSearches = searches.slice(0, HARD_QUERY_CAP);

config._abortRun = false;
config._abortReason = '';

return [{ json: config }];

// Split LinkedIn searches into individual items
const config = $input.first().json;

if (config._abortRun) {
  console.log(config._abortReason || 'Run aborted by guard.');
  return [];
}

const scope = config.workflowScope || 'default';
const staticData = $getWorkflowStaticData('global');

// Guard 1: never emit twice within the same execution
const execGuardKey = `splitLastExecutionId_${scope}`;
const currentExecutionId = String($execution.id || '');
if (staticData[execGuardKey] === currentExecutionId) {
  return [];
}
staticData[execGuardKey] = currentExecutionId;

const searches = Array.isArray(config.linkedinSearches) ? config.linkedinSearches : [];

// Safety dedupe in case upstream config accidentally repeats query tuples
const seen = new Set();
const uniqueSearches = [];
for (const search of searches) {
  const key = [
    search.keywords,
    search.location,
    search.workType,
    search.datePosted,
    search.windowId || 'primary'
  ]
    .map(v => String(v || '').toLowerCase().trim())
    .join('|');

  if (seen.has(key)) continue;
  seen.add(key);
  uniqueSearches.push(search);
}

// Guard 2 (global fail-safe): max 10 actor calls per role per 15-minute window
const HARD_MAX_QUERIES = 10;
const BUDGET_WINDOW_MINUTES = 15;
const budgetKey = `splitBudget_${scope}`;
const now = Date.now();
let budget = staticData[budgetKey] || { windowStartMs: now, count: 0 };

const windowMs = BUDGET_WINDOW_MINUTES * 60 * 1000;
if (!budget.windowStartMs || (now - Number(budget.windowStartMs)) >= windowMs) {
  budget = { windowStartMs: now, count: 0 };
}

const configuredMax = Math.max(1, Number(config.maxQueriesPerRun ?? HARD_MAX_QUERIES));
const remainingBudget = Math.max(0, HARD_MAX_QUERIES - Number(budget.count || 0));
const effectiveMax = Math.min(HARD_MAX_QUERIES, configuredMax, remainingBudget);

if (effectiveMax <= 0) {
  return [];
}

const finalSearches = uniqueSearches.slice(0, effectiveMax);

budget.count = Number(budget.count || 0) + finalSearches.length;
staticData[budgetKey] = budget;

return finalSearches.map((search, idx) => ({
  json: {
    ...search,
    _queryIndex: idx + 1,
    _queryCount: finalSearches.length,
    fetchFullDescription: typeof search.fetchFullDescription === 'boolean'
      ? search.fetchFullDescription
      : !!config.fetchFullDescription,
    enrichWithAI: !!config.enrichWithAI,
    actorProxyConfig: config.actorProxyConfig || {},
    _config: config,
  }
}));

// Normalize Mfrostbutter/linkedin-jobs-scraper output to unified job schema
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  // Our actor always emits title + companyName; skip empty records
  if (!d || !d.title) continue;

  const loc = d.location || '';
  const workplaceType = d.workRemoteAllowed
    ? (d.workplaceTypes && d.workplaceTypes[0]) || 'Remote'
    : 'On-site';

  // salary_low/salary_high come from parser; salary is the raw string
  let salaryMin = d.salary_low || null;
  let salaryMax = d.salary_high || null;

  // Carry config forward when available. Actor dataset items usually drop upstream fields,
  // so fallback to Config node when this workflow path includes it.
  let cfg = item.json._config;
  if (!cfg) {
    try {
      cfg = $('Config').first()?.json || null;
    } catch (e) {
      cfg = null;
    }
  }

  results.push({
    jobTitle: d.title || '',
    company: d.companyName || '',
    location: loc,
    source: 'LinkedIn',
    sourceId: d.id || `li-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    sourceUrl: d.link || d.applyUrl || '',
    postedDate: d.postedAt || new Date().toISOString(),
    salaryMin: salaryMin,
    salaryMax: salaryMax,
    employmentType: 'Full-time',
    workplaceType: workplaceType,
    companySize: '',
    companyIndustry: '',
    descriptionSnippet: (d.descriptionText || '').substring(0, 500),
    fullDescription: d.descriptionText || '',
    easyApply: false,
    applicants: null,
    _config: cfg,
  });
}

return results.map(r => ({ json: r }));

// ===== DEDUP + SCORE =====
// Deduplicates within batch and scores each job for relevance.
// Every keyword list comes from the Config node's scoring block;
// the DEFAULTS below only apply if Config is missing.

const items = $input.all();

const DEFAULT_SCORING = {
  titleKeywords: [],
  partialKeywords: ['engineer', 'architect', 'developer', 'platform', 'data'],
  seniorityWords: ['senior', 'staff', 'principal', 'lead', 'architect'],
  homeAreaKeywords: [],
  bonusJDKeywords: [],
  secondaryHubKeywords: [],
  salaryFloor: 0,
  negativeTitlePatterns: ['\\b(intern|junior|entry.level)\\b'],
  highRelevanceThreshold: 60,
};

function getScoringConfig() {
  const fromItem = items[0]?.json?._config?.scoring;
  if (fromItem && typeof fromItem === 'object') return { ...DEFAULT_SCORING, ...fromItem };
  return DEFAULT_SCORING;
}

const config = getScoringConfig();
const salaryFloor = Math.max(0, Number(config.salaryFloor || 0));

// Dedup within batch by normalized title + company
const seen = new Set();
const unique = [];
for (const item of items) {
  const d = item.json;
  const key = `${(d.jobTitle || '').toLowerCase().trim()}|${(d.company || '').toLowerCase().trim()}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(d);
}

// Scoring function
function scoreJob(job) {
  let score = 0;
  const breakdown = [];
  const titleLower = (job.jobTitle || '').toLowerCase();
  const descLower = (job.fullDescription || '').toLowerCase();

  // Title exact match (+30)
  const exactMatch = config.titleKeywords.some(kw => titleLower.includes(String(kw).toLowerCase()));
  if (exactMatch) {
    score += 30;
    breakdown.push('Title exact match: +30');
  } else {
    // Partial keyword match (+15)
    const hasPartial = config.partialKeywords.some(kw => titleLower.includes(String(kw).toLowerCase()));
    if (hasPartial) {
      score += 15;
      breakdown.push('Title partial match: +15');
    }
  }

  // Seniority signal (+5)
  if (config.seniorityWords.some(w => titleLower.includes(String(w).toLowerCase()))) {
    score += 5;
    breakdown.push('Senior title: +5');
  }

  // Location: Remote/Hybrid (+20), home area (+15)
  const locLower = (job.location || '').toLowerCase();
  const wpLower = (job.workplaceType || '').toLowerCase();
  if (wpLower.includes('remote') || locLower.includes('remote')) {
    score += 20;
    breakdown.push('Remote: +20');
  } else if (wpLower.includes('hybrid') || locLower.includes('hybrid')) {
    score += 20;
    breakdown.push('Hybrid: +20');
  } else if (config.homeAreaKeywords.some(kw => locLower.includes(String(kw).toLowerCase()))) {
    score += 15;
    breakdown.push('Home area: +15');
  }

  // Salary at or above the configured floor (+10 / +5)
  if (salaryFloor > 0) {
    if (job.salaryMin && job.salaryMin >= salaryFloor) {
      score += 10;
      breakdown.push(`Salary >= $${salaryFloor}: +10`);
    } else if (job.salaryMax && job.salaryMax >= salaryFloor) {
      score += 5;
      breakdown.push(`Salary range includes $${salaryFloor}+: +5`);
    }
  }

  // Mid-market company 100-2000 employees (+10)
  const sizeStr = (job.companySize || '').replace(/,/g, '');
  const sizeMatch = sizeStr.match(/(\d+)/);
  if (sizeMatch) {
    const size = parseInt(sizeMatch[1]);
    if (size >= 100 && size <= 2000) {
      score += 10;
      breakdown.push('Mid-market company (100-2K): +10');
    } else if (size > 2000 && size <= 10000) {
      score += 5;
      breakdown.push('Large company (2K-10K): +5');
    }
  }

  // Bonus JD keywords in description (+10)
  const hasBonus = config.bonusJDKeywords.some(kw => descLower.includes(String(kw).toLowerCase()));
  if (hasBonus) {
    score += 10;
    breakdown.push('Bonus JD keyword match: +10');
  }

  // Negative title patterns (-20 each)
  for (const pat of config.negativeTitlePatterns || []) {
    try {
      if (titleLower.match(new RegExp(pat, 'i'))) {
        score -= 20;
        breakdown.push(`Negative title pattern (${pat}): -20`);
      }
    } catch (e) { /* bad regex in config; skip */ }
  }

  return {
    relevanceScore: Math.max(0, Math.min(100, score)),
    scoreBreakdown: JSON.stringify(breakdown),
    isHighRelevance: score >= config.highRelevanceThreshold,
    bonusKeywordMatch: hasBonus
  };
}

// Score each job
const scored = unique.map(job => {
  const scores = scoreJob(job);
  return {
    json: {
      ...job,
      ...scores,
      firstSeen: new Date().toISOString(),
      lastSeen: new Date().toISOString(),
      status: 'New'
    }
  };
});

// Sort by relevance score descending
scored.sort((a, b) => b.json.relevanceScore - a.json.relevanceScore);

// ===== DUAL-HUB OFFICE DETECTION (optional) =====
// If you configure BOTH homeAreaKeywords and secondaryHubKeywords, companies
// posting the same search in both hubs get +15 (signals a real presence in
// your area rather than a one-off posting).
const homeKws = config.homeAreaKeywords || [];
const hubKws = config.secondaryHubKeywords || [];
if (homeKws.length && hubKws.length) {
  const companiesByRegion = {};
  for (const item of scored) {
    const company = (item.json.company || '').toLowerCase().trim();
    if (!company) continue;
    const loc = (item.json.location || '').toLowerCase();
    const isHub = hubKws.some(kw => loc.includes(String(kw).toLowerCase()));
    const isHome = homeKws.some(kw => loc.includes(String(kw).toLowerCase()));
    if (!companiesByRegion[company]) companiesByRegion[company] = { home: false, hub: false };
    if (isHub) companiesByRegion[company].hub = true;
    if (isHome) companiesByRegion[company].home = true;
  }

  for (const item of scored) {
    const company = (item.json.company || '').toLowerCase().trim();
    const isDual = !!(companiesByRegion[company] && companiesByRegion[company].home && companiesByRegion[company].hub);
    item.json.dualHubOffice = isDual;
    if (isDual) {
      item.json.relevanceScore = Math.min(100, item.json.relevanceScore + 15);
      const breakdown = JSON.parse(item.json.scoreBreakdown || '[]');
      breakdown.push('Dual-hub office: +15');
      item.json.scoreBreakdown = JSON.stringify(breakdown);
    }
  }

  // Re-sort after dual-hub bonus
  scored.sort((a, b) => b.json.relevanceScore - a.json.relevanceScore);
}

return scored;

const items = $input.all();

let cfg = items[0]?.json?._config || null;
if (!cfg) { try { cfg = $('Dedup and Score').first()?.json?._config || null; } catch {} }

// Empty webhook URL = Slack disabled; the "Has Notifications?" gate then skips the post.
const slackWebhookUrl = cfg?.slackWebhookUrl || '';

let succeeded = 0;
let rateLimited = 0;
let otherFailed = 0;
for (const i of items) {
  const j = i.json || {};
  if (j.job_id) succeeded += 1;
  else if (Array.isArray(j.errors) && j.errors.some(e => (e.error||'').includes('RATE_LIMIT'))) rateLimited += 1;
  else if (j.errors || j.error) otherFailed += 1;
}
const total = items.length;
// count drives the Slack gate: zero it out when Slack is disabled.
const count = slackWebhookUrl ? succeeded : 0;

let message;
if (total === 0) {
  message = 'No new jobs added.';
} else if (rateLimited === 0 && otherFailed === 0) {
  message = `${succeeded} new jobs added to the jobs database.`;
} else {
  message = `Postgres: ${succeeded} added, ${rateLimited} rate-limited, ${otherFailed} other failed (out of ${total}).`;
}

return [{ json: { message, count, succeeded, rateLimited, otherFailed, total, slackWebhookUrl } }];

